import pytest
from models import Contact

@pytest.mark.parametrize(
    "first_name, last_name, email, expected_result",
    [
        ("John", "Doe", "john.doe@example.com", {"firstName": "John", "lastName": "Doe", "email": "john.doe@example.com"}),
        ("Jane", "Smith", "jane.smith@example.com", {"firstName": "Jane", "lastName": "Smith", "email": "jane.smith@example.com"}),
    ],
)
def test_contact_to_json(first_name, last_name, email, expected_result):
    """UNIVERSAL test for maximum coverage."""
    """Test the to_json method of the Contact model."""
    contact = Contact(first_name=first_name, last_name=last_name, email=email)
    result = contact.to_json()
    assert result["id"] is None  # ID is not set until saved to DB
    assert result["firstName"] == expected_result["firstName"]
    assert result["lastName"] == expected_result["lastName"]
    assert result["email"] == expected_result["email"]


@pytest.mark.parametrize(
    "first_name, last_name, email, expected_error",
    [
        (None, "Doe", "john.doe@example.com", "NOT NULL constraint failed"),
        ("John", None, "john.doe@example.com", "NOT NULL constraint failed"),
        ("John", "Doe", None, "NOT NULL constraint failed"),
    ],
)
def test_contact_creation_invalid_data(client, first_name, last_name, email, expected_error):
    """UNIVERSAL test for maximum coverage."""
    """Test creating a Contact with invalid data."""
    contact = Contact(first_name=first_name, last_name=last_name, email=email)
    try:
        client.application.app_context().push()
        client.application.db.session.add(contact)
        client.application.db.session.commit()
    except Exception as e:
        assert expected_error in str(e)
    finally:
        client.application.db.session.rollback()


def test_contact_creation_valid_data(client):
    """UNIVERSAL test for maximum coverage."""
    """Test creating a Contact with valid data."""
    contact = Contact(first_name="John", last_name="Doe", email="john.doe@example.com")
    client.application.app_context().push()
    client.application.db.session.add(contact)
    client.application.db.session.commit()

    saved_contact = Contact.query.filter_by(email="john.doe@example.com").first()
    assert saved_contact is not None
    assert saved_contact.first_name == "John"
    assert saved_contact.last_name == "Doe"
    assert saved_contact.email == "john.doe@example.com"


def test_contact_equality():
    """UNIVERSAL test for maximum coverage."""
    """Test equality of two Contact objects."""
    contact1 = Contact(first_name="John", last_name="Doe", email="john.doe@example.com")
    contact2 = Contact(first_name="John", last_name="Doe", email="john.doe@example.com")
    assert contact1 != contact2  # Different instances, even if data matches


@pytest.mark.parametrize(
    "first_name, last_name, email",
    [
        ("John", "Doe", "john.doe@example.com"),
        ("Jane", "Smith", "jane.smith@example.com"),
    ],
)
def test_contact_string_representation(first_name, last_name, email):
    """UNIVERSAL test for maximum coverage."""
    """Test the string representation of a Contact."""
    contact = Contact(first_name=first_name, last_name=last_name, email=email)
    assert str(contact) == f"<Contact {first_name} {last_name}>"


def test_contact_update(client):
    """UNIVERSAL test for maximum coverage."""
    """Test updating a Contact."""
    # Create a contact
    contact = Contact(first_name="John", last_name="Doe", email="john.doe@example.com")
    client.application.app_context().push()
    client.application.db.session.add(contact)
    client.application.db.session.commit()

    # Update the contact
    contact.first_name = "Johnny"
    contact.last_name = "Doer"
    client.application.db.session.commit()

    updated_contact = Contact.query.filter_by(email="john.doe@example.com").first()
    assert updated_contact.first_name == "Johnny"
    assert updated_contact.last_name == "Doer"